import React from "react";
import { Link } from "react-router-dom";
import Logo from "../assets/Logo.svg"

const Navbar = ()=> {

    return (
        <div>
            <Link to="/">
             <img src= {Logo} alt="Logo" width={160} height={32} loading="lazy"></img> 
            </Link>
            <nav>
                <ul>
                    <li>
                        <Link to="/"></Link>
                    </li>
                </ul>
            </nav>

        </div>
    )
}

export default Navbar;
